function absUrl(url, base) {
  if (!url) return "";
  try { return new URL(htmlDecode(url), base || currentUrl() || KETSU_BASE_URL).href; }
  catch (e) {
    if (String(url).indexOf("//") === 0) return "https:" + url;
    if (String(url).charAt(0) === "/") return (base || KETSU_BASE_URL).replace(/\/$/, "") + url;
    return url;
  }
