function humanizeSlug(value) {
  value = htmlDecode(String(value || ""));
  value = value.split(/[?#]/)[0].replace(/\/+$/, "");
  value = value.substring(value.lastIndexOf("/") + 1);
  value = value.replace(/\.(html?|json)$/i, "");
  value = value.replace(/^(novel|book|manga|series|comic|comics|chapter|chapters)[-_]/i, "");
  value = value.replace(/[-_]+/g, " ").replace(/\b\w/g, function (m) { return m.toUpperCase(); });
  return cleanText(value);
}
function looksIdentifierSegment(value) {
  var t = cleanText(String(value || ""));
  return !t
    || /^(manga|novel|book|series|comic|comics|title|chapter|chapters|read|viewer)$/i.test(t)
    || /^[0-9]+(?:\.[0-9]+)?$/.test(t)
    || /^[0-9]{4}[-/.][0-9]{1,2}[-/.][0-9]{1,2}$/.test(t)
