function titleFromLink(link) {
  try {
    var url = new URL(absUrl(link), KETSU_BASE_URL);
    var param = url.searchParams.get("title") || url.searchParams.get("page") || url.searchParams.get("name") || url.searchParams.get("keyword") || url.searchParams.get("q");
