function looksGenericTitle(value) {
  var t = cleanText(value || "");
  if (!t) return true;
  if (/^[0-9]+(?:\.[0-9]+)?$/.test(t)) return true;
  if (/^[0-9]{4}[-/.][0-9]{1,2}[-/.][0-9]{1,2}$/.test(t)) return true;
  if (/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(t)) return true;
  if (/^(chapter|ch\.?|episode|ep\.?|page)\s*[0-9]+(?:\.[0-9]+)?$/i.test(t)) return true;
  return /^(untitled|series|manga|novel|book|comic|title)$/i.test(t)
    || /^(scribble hub series|mangapill manga|novelfire|novelbin|freewebnovel|readnovelfull|novgo|novelcool|webtoon)$/i.test(t)
    || /^(royal road|baka-tsuki|mangadex|weebcentral|mangakatana|asura scans)$/i.test(t);
}
function cleanPageTitle(value, link) {
  var cleanTitle = cleanText(value || "");
  var fallback = titleFromLink(link);
  if (looksGenericTitle(cleanTitle) && fallback) cleanTitle = fallback;
  cleanTitle = cleanTitle.replace(/\s+\|\s*(Scribble Hub|NovelFire|NovelBin|Mangapill|MangaDex|WEBTOON).*$/i, "");
  cleanTitle = cleanTitle.replace(/\s+-\s*(Scribble Hub|NovelFire|NovelBin|Mangapill|MangaDex|WEBTOON).*$/i, "");
  cleanTitle = cleanText(cleanTitle);
  if (looksGenericTitle(cleanTitle)) cleanTitle = "";
  return cleanTitle || (fallback && !looksGenericTitle(fallback) ? fallback : "") || "Untitled";
}
function chapterTitleFromLink(link, fallback) {
  var raw = cleanText(fallback || "");
  var slug = titleFromLink(link);
  var source = raw || slug;
  var m = source.match(/\b(?:chapter|ch\.?)\s*([0-9]+(?:\.[0-9]+)?[a-z]?)(.*)$/i);
  if (!m && slug) m = slug.match(/\b(?:chapter|ch\.?)\s*([0-9]+(?:\.[0-9]+)?[a-z]?)(.*)$/i);
  if (m) {
    var rest = cleanText((m[2] || "").replace(/^[-:.\s]+/, ""));
    rest = rest.replace(/\s+(Mangapill|NovelFire|Chapter)$/i, "");
    return "Chapter " + m[1] + (rest && rest.length <= 70 ? ": " + rest : "");
  }
  return raw || slug || "Chapter";
}
