}
function emitPageAppend(kind, data, sectionName, nextUrl) {
  var state = getSaved();
  var output = state.output || [];
  if (output.length === 1) {
    var first = output[0] || {};
    var firstSection = first.section || {};
    var firstData = first.data && first.data.length ? first.data[0] : null;
    var firstLink = firstData && firstData.link ? firstData.link.url : "";
    if (!firstSection.sectionName && firstData && !firstData.title && !firstLink) output = [];
  }
  output.push(new PageOutput("wide6", "vertical", "longDoubletsFull", "leading", new Section(sectionName || "", true), defaultLayout(), data));
