function cardRoot(el) {
  var node = el;
  for (var depth = 0; depth < 7 && node; depth++) {
    if (node.querySelector && node.querySelector('a[href*="/book/"]') && (node.querySelector("img") || /novel|book|item|row|list/i.test(attr(node, "class")))) return node;
    node = node.parentNode;
  }
  return el;
}
var links = document.querySelectorAll('a[href*="/book/"]');
for (var i = 0; i < links.length; i++) {
  var a = links[i];
  var href = attr(a, "href");
  if (!href || /\/chapter-/.test(href)) continue;
  var item = cardRoot(a);
  var sameBookLinks = item.querySelectorAll('a[href*="/book/"]');
  for (var j = 0; j < sameBookLinks.length; j++) {
    var candidateHref = attr(sameBookLinks[j], "href");
    if (candidateHref && !/\/chapter-/.test(candidateHref)) { a = sameBookLinks[j]; href = candidateHref; break; }
  }
  if (!a) continue;
  var link = absUrl(href, KETSU_BASE_URL);
  var title = text(item.querySelector(".novel-title a, .novel-title, h3 a, h4 a, .title a, .title")) || attr(a, "title") || text(a) || titleFromLink(link);
  var img = item.querySelector(".novel-cover img, .book-cover img, .cover img, img") || a.querySelector("img");
  var cover = attr(img, "data-src") || attr(img, "src") || attr(img, "data-original");
  var desc = text(item.querySelector(".summary, .description, .desc, .novel-summary"));
  var stat = text(item.querySelector(".novel-stats, .stats, .rating, .latest"));
  uniquePush(data, seen, link, pageData(link, cover, title, desc, stat, "NovelFire", "Text", ""));
}
emitPageAppend("main", data, "NovelFire Ranking", "https://novelfire.net/latest-release");

